'use strict'
var inputName = document.querySelector('#first-name'),
	inputMail = document.querySelector('#mail'),
	inputMsg = document.querySelector('#contact-area'),
	popUp = document.querySelector('.popup'),
	btnContact = document.querySelector('.contact__box-form-btn'),
	btnClose = document.querySelector('.popup-btn'),
	arrayInputs = [inputName, inputMail, inputMsg],
	hideError = function (e) {
		e = e.parentElement.querySelector('.name-error')
		;(e.style.visibility = 'hidden'), (e.textContent = '')
	},
	showError = function (e, t) {
		e = e.parentElement.querySelector('.name-error')
		;(e.style.visibility = 'visible'), (e.textContent = t)
	},
	startForm = function () {
		'' !== inputName.value && '' !== inputMail.value && '' !== inputMsg.value && showPopup()
	},
	checkForm = function (e) {
		e.forEach(function (e) {
			'' === e.value ? showError(e, 'To pole nie może być puste!') : (hideError(e), checkMail(inputMail))
		})
	},
	checkMail = function (e) {
		;/^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,3}))$/.test(
			e.value
		)
			? (startForm(), hideError(e))
			: e.value.length < 1
			? showError(e, 'To pole nie może być puste!')
			: showError(e, 'Wpisz poprawny adres e-mail!')
	},
	showPopup = function () {
		popUp.style.display = 'flex'
	},
	hidePopup = function () {
		;(inputName.value = ''), (inputMail.value = ''), (inputMsg.value = ''), (popUp.style.display = 'none')
	}
btnContact.addEventListener('click', function () {
	checkForm(arrayInputs)
}),
	btnClose.addEventListener('click', hidePopup)
